create table rmais_combinacao_guias (
    id_combinacao  number generated by default on null as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 cache
    20 noorder nocycle nokeep noscale not null enable,
    fk_site        number not null enable,
    cnpj_receiver  varchar2(20 byte) not null enable,
    centro_custo   varchar2(5 char) not null enable,
    conta_contabil varchar2(10 char) not null enable
);

alter table rmais_combinacao_guias
    add constraint rmais_combinacao_guias_pk primary key ( id_combinacao )
        using index enable;


